  "type": "FLIP_CARD",
  "lessonText": "Learn the names of the piano keys to build a strong foundation.",
  "data": {
    "cards": [
      {
        "front": "What are the white keys on the piano called?",
        "back": "They are called natural keys.",
        "icon": "🎹"
      },
      {
        "front": "What are the black keys on the piano called?",
        "back": "They are called sharp and flat keys.",
        "icon": "🎶"
      },
      {
        "front": "How many keys are on a standard piano?",
        "back": "A standard piano has 88 keys.",
        "icon": "🔑"
      },
      {
        "front": "What is the name of the first white key?",
        "back": "The first white key is called 'C'.",
        "icon": "🎵"
      }
    ]
  }
}
